-- GDCU course content restore: rebuilds content tables + loads data
USE `u514321141_gdcu`;
SET FOREIGN_KEY_CHECKS=0;
SET NAMES utf8mb4;

DROP TABLE IF EXISTS `assignments`;
DROP TABLE IF EXISTS `quiz_options`;
DROP TABLE IF EXISTS `quiz_questions`;
DROP TABLE IF EXISTS `quizzes`;
DROP TABLE IF EXISTS `lesson_materials`;
DROP TABLE IF EXISTS `lessons`;
DROP TABLE IF EXISTS `modules`;
DROP TABLE IF EXISTS `course_shared_modules`;
DROP TABLE IF EXISTS `shared_modules`;
DROP TABLE IF EXISTS `courses`;
DROP TABLE IF EXISTS `programs`;

CREATE TABLE `programs` (
  `id` int unsigned NOT NULL AUTO_INCREMENT,
  `slug` varchar(255) NOT NULL,
  `title` varchar(255) NOT NULL,
  `level` varchar(255) NOT NULL,
  `school` varchar(255) NOT NULL,
  `credential` varchar(255) NULL,
  `summary` text NOT NULL,
  `description` text NULL,
  `duration` varchar(255) NULL,
  `study_mode` varchar(255) NULL,
  `tuition` double NULL,
  `tuition_currency` varchar(255) NULL DEFAULT 'GBP',
  `image_url` varchar(255) NULL,
  `icon` varchar(255) NULL,
  `featured` tinyint(1) NOT NULL DEFAULT 0,
  `published` tinyint(1) NOT NULL DEFAULT 1,
  `sort_order` int NOT NULL DEFAULT 0,
  `created_at` datetime NOT NULL DEFAULT CURRENT_TIMESTAMP,
  `updated_at` datetime NOT NULL DEFAULT CURRENT_TIMESTAMP,
  PRIMARY KEY (`id`)
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4;


CREATE TABLE `courses` (
  `id` int unsigned NOT NULL AUTO_INCREMENT,
  `slug` varchar(255) NOT NULL,
  `program_id` int NULL,
  `instructor_id` int NULL,
  `code` varchar(255) NULL,
  `title` varchar(255) NOT NULL,
  `summary` text NULL,
  `description` text NULL,
  `credits` int NOT NULL DEFAULT 15,
  `icon` varchar(255) NULL,
  `published` tinyint(1) NOT NULL DEFAULT 1,
  `sort_order` int NOT NULL DEFAULT 0,
  `created_at` datetime NOT NULL DEFAULT CURRENT_TIMESTAMP,
  `updated_at` datetime NOT NULL DEFAULT CURRENT_TIMESTAMP,
  `drip_feed_enabled` tinyint(1) NOT NULL DEFAULT 0,
  `drip_feed_interval_hours` int NOT NULL DEFAULT 4,
  `featured_image` varchar(255) NULL,
  `year_level` int NOT NULL DEFAULT 1,
  `category` varchar(255) NULL,
  PRIMARY KEY (`id`)
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4;


CREATE TABLE `shared_modules` (
  `id` int unsigned NOT NULL AUTO_INCREMENT,
  `code` varchar(255) NOT NULL,
  `title` varchar(255) NOT NULL,
  `description` text NULL,
  `summary` text NULL,
  `year_level` int NOT NULL DEFAULT 1,
  `category` varchar(255) NULL,
  `featured_image` varchar(255) NULL,
  `published` tinyint(1) NOT NULL DEFAULT 1,
  `created_at` datetime NOT NULL DEFAULT CURRENT_TIMESTAMP,
  `updated_at` datetime NOT NULL DEFAULT CURRENT_TIMESTAMP,
  PRIMARY KEY (`id`)
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4;


CREATE TABLE `course_shared_modules` (
  `id` int unsigned NOT NULL AUTO_INCREMENT,
  `course_id` int NOT NULL,
  `shared_module_id` int NOT NULL,
  `sort_order` int NOT NULL DEFAULT 0,
  PRIMARY KEY (`id`)
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4;


CREATE TABLE `modules` (
  `id` int unsigned NOT NULL AUTO_INCREMENT,
  `course_id` int NOT NULL,
  `title` varchar(255) NOT NULL,
  `summary` text NULL,
  `sort_order` int NOT NULL DEFAULT 0,
  `release_date` datetime NULL,
  `prerequisite_module_id` int NULL,
  `essay_required` tinyint(1) NOT NULL DEFAULT 0,
  `essay_prompt` text NULL,
  `featured_image` varchar(255) NULL,
  `shared_module_id` int NULL,
  `year_level` int NOT NULL DEFAULT 1,
  PRIMARY KEY (`id`)
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4;


CREATE TABLE `lessons` (
  `id` int unsigned NOT NULL AUTO_INCREMENT,
  `module_id` int NOT NULL,
  `title` varchar(255) NOT NULL,
  `type` varchar(255) NOT NULL DEFAULT 'reading',
  `content` text NULL,
  `video_url` varchar(255) NULL,
  `duration_min` int NOT NULL DEFAULT 15,
  `sort_order` int NOT NULL DEFAULT 0,
  `image_url` varchar(255) NULL,
  `block_no` int NULL,
  `block_title` varchar(255) NULL,
  `live_provider` varchar(255) NULL,
  `live_join_url` text NULL,
  `live_embed_url` text NULL,
  `live_passcode` varchar(255) NULL,
  PRIMARY KEY (`id`)
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4;


CREATE TABLE `lesson_materials` (
  `id` int unsigned NOT NULL AUTO_INCREMENT,
  `lesson_id` int NOT NULL,
  `label` varchar(255) NOT NULL,
  `url` varchar(255) NOT NULL,
  `type` varchar(255) NOT NULL DEFAULT 'link',
  `sort_order` int NOT NULL DEFAULT 0,
  PRIMARY KEY (`id`)
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4;

CREATE TABLE `quizzes` (
  `id` int unsigned NOT NULL AUTO_INCREMENT,
  `course_id` int NULL,
  `title` varchar(255) NOT NULL,
  `description` text NULL,
  `pass_mark` int NOT NULL DEFAULT 60,
  `time_limit_min` int NULL,
  `sort_order` int NOT NULL DEFAULT 0,
  `module_id` int NULL,
  `lesson_id` int NULL,
  `max_attempts` int NULL,
  `randomize_questions` tinyint(1) NOT NULL DEFAULT 0,
  `feedback_mode` varchar(255) NOT NULL DEFAULT 'immediate',
  `is_final_exam` tinyint(1) NOT NULL DEFAULT 0,
  `exam_scope` varchar(255) NOT NULL DEFAULT 'course',
  `program_id` int NULL,
  `exam_year` int NULL,
  `after_block` int NULL,
  `covers_blocks` varchar(255) NULL,
  PRIMARY KEY (`id`)
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4;


CREATE TABLE `quiz_questions` (
  `id` int unsigned NOT NULL AUTO_INCREMENT,
  `quiz_id` int NOT NULL,
  `prompt` text NOT NULL,
  `type` varchar(255) NOT NULL DEFAULT 'single',
  `explanation` text NULL,
  `sort_order` int NOT NULL DEFAULT 0,
  PRIMARY KEY (`id`)
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4;


CREATE TABLE `quiz_options` (
  `id` int unsigned NOT NULL AUTO_INCREMENT,
  `question_id` int NOT NULL,
  `text` text NOT NULL,
  `is_correct` tinyint(1) NOT NULL DEFAULT 0,
  `sort_order` int NOT NULL DEFAULT 0,
  PRIMARY KEY (`id`)
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4;


CREATE TABLE `assignments` (
  `id` int unsigned NOT NULL AUTO_INCREMENT,
  `course_id` int NOT NULL,
  `title` varchar(255) NOT NULL,
  `instructions` text NULL,
  `due_date` text NULL,
  `max_points` int NOT NULL DEFAULT 100,
  `published` tinyint(1) NOT NULL DEFAULT 1,
  `created_at` datetime NOT NULL DEFAULT CURRENT_TIMESTAMP,
  `updated_at` datetime NOT NULL DEFAULT CURRENT_TIMESTAMP,
  `module_id` int NULL,
  `lesson_block_id` int NULL,
  `sort_order` int NOT NULL DEFAULT 0,
  `assignment_type` varchar(255) NOT NULL DEFAULT 'essay',
  PRIMARY KEY (`id`)
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4;



CREATE TABLE IF NOT EXISTS `knex_migrations` (`id` int unsigned NOT NULL AUTO_INCREMENT, `name` varchar(255), `batch` int, `migration_time` timestamp NULL DEFAULT CURRENT_TIMESTAMP, PRIMARY KEY (`id`));
CREATE TABLE IF NOT EXISTS `knex_migrations_lock` (`index` int unsigned NOT NULL AUTO_INCREMENT, `is_locked` int, PRIMARY KEY (`index`));
DELETE FROM `knex_migrations`;
UPDATE `knex_migrations_lock` SET `is_locked` = 0;

