INSERT INTO `programs` (`id`, `slug`, `title`, `level`, `school`, `credential`, `summary`, `description`, `duration`, `study_mode`, `tuition`, `tuition_currency`, `image_url`, `icon`, `featured`, `published`, `sort_order`, `created_at`, `updated_at`) VALUES
(73, 'certificate-biblical-studies', 'Certificate in Biblical Studies', 'Certificate', 'School of Global Theology', 'Certificate of Higher Education', 'A foundational certificate on Scripture, Bible study methods and Christian doctrine.', 'Study the Bible’s structure, literary genres and theological themes with this introductory certificate. Ideal for new students, lay leaders and church staff who want a strong biblical foundation.', '6 months (online)', 'Online', 1200, 'GBP', '/img/generated/gdcu-program-theology-living-room-v2.webp', 'menu_book', 0, 1, 1, '2026-07-02 16:11:13', '2026-07-02 16:11:13'),
(74, 'certificate-christian-ministry', 'Certificate in Christian Ministry', 'Certificate', 'School of Ministry Practice', 'Certificate of Higher Education', 'Practical ministry skills for service, teaching and church life.', 'Develop leadership, preaching, pastoral care and discipleship skills for effective Christian ministry. This certificate is designed for emerging leaders, volunteers and church workers.', '6 months (online)', 'Online', 1250, 'GBP', '/img/generated/gdcu-student-video-lesson-home.webp', 'church', 0, 1, 2, '2026-07-02 16:11:13', '2026-07-02 16:11:13'),
(75, 'certificate-pastoral-care', 'Certificate in Pastoral Care', 'Certificate', 'School of Pastoral Studies', 'Certificate of Higher Education', 'Care skills for counseling, crisis support and spiritual presence.', 'Learn the essentials of pastoral care, active listening and spiritual accompaniment. This certificate equips students to support individuals, families and congregations with compassion.', '6 months (online)', 'Online', 1250, 'GBP', '/img/generated/gdcu-student-courtyard-learning.webp', 'support', 0, 1, 3, '2026-07-02 16:11:13', '2026-07-02 16:11:13'),
(76, 'certificate-chaplaincy-spiritual-care', 'Certificate in Chaplaincy and Spiritual Care', 'Certificate', 'School of Pastoral Studies', 'Certificate of Higher Education', 'Foundational training for chaplains in hospitals, prisons, schools and organisations.', 'Prepare to offer spiritual presence, interfaith sensitivity and pastoral care in chaplaincy settings. The certificate focuses on ethics, crisis ministry and reflective practice.', '6 months (online)', 'Online', 1300, 'GBP', '/img/generated/gdcu-program-leadership-park-v2.webp', 'local_hospital', 0, 1, 4, '2026-07-02 16:11:13', '2026-07-02 16:11:13'),
(77, 'certificate-christian-leadership', 'Certificate in Christian Leadership', 'Certificate', 'School of Global Leadership', 'Certificate of Higher Education', 'Principles of Christ-centred leadership for church and community.', 'Study leadership from a biblical perspective, including team formation, vision casting and character development. This certificate helps leaders serve with humility and strategic clarity.', '6 months (online)', 'Online', 1250, 'GBP', '/img/generated/gdcu-program-leadership-park-v2.webp', 'diversity_3', 0, 1, 5, '2026-07-02 16:11:13', '2026-07-02 16:11:13'),
(78, 'certificate-missions-diaspora-ministry', 'Certificate in Missions and Diaspora Ministry', 'Certificate', 'School of Global Theology', 'Certificate of Higher Education', 'Engage diaspora communities with mission strategy, cultural intelligence and gospel partnership.', 'This certificate explores migration, diaspora identity and mission practice. Students learn to build culturally effective ministry and sustainable church partnerships.', '6 months (online)', 'Online', 1300, 'GBP', '/img/generated/gdcu-student-admissions-video.webp', 'public', 0, 1, 6, '2026-07-02 16:11:13', '2026-07-02 16:11:13'),
(79, 'certificate-church-administration', 'Certificate in Church Administration', 'Certificate', 'School of Ministry Practice', 'Certificate of Higher Education', 'Administration, finance and governance skills for healthy church operations.', 'Learn budgeting, governance, events coordination and volunteer management for church settings. This certificate is ideal for church administrators and lay leaders.', '6 months (online)', 'Online', 1200, 'GBP', '/img/generated/gdcu-student-video-lesson-home.webp', 'admin_panel_settings', 0, 1, 7, '2026-07-02 16:11:13', '2026-07-02 16:11:13'),
(80, 'certificate-prayer-discipleship-spiritual-formation', 'Certificate in Prayer, Discipleship and Spiritual Formation', 'Certificate', 'School of Spiritual Formation', 'Certificate of Higher Education', 'Deepen your prayer life and disciple others through spiritual formation practices.', 'This certificate teaches spiritual disciplines, prayer frameworks and discipleship rhythms. Students learn how to nurture their own devotion while mentoring others in spiritual growth.', '6 months (online)', 'Online', 1200, 'GBP', '/img/generated/gdcu-program-theology-living-room-v2.webp', 'self_improvement', 0, 1, 8, '2026-07-02 16:11:13', '2026-07-02 16:11:13'),
(81, 'diploma-biblical-studies', 'Diploma in Biblical Studies', 'Diploma', 'School of Global Theology', 'Undergraduate Diploma', 'A deeper study of Old and New Testament themes, books and theology.', 'This diploma examines biblical theology, historical context and interpretive methods for both Testaments. Students develop a rich understanding of the Bible’s unity and message.', '1 year (online)', 'Online', 2800, 'GBP', '/img/generated/gdcu-student-courtyard-learning.webp', 'menu_book', 0, 1, 9, '2026-07-02 16:11:13', '2026-07-02 16:11:13'),
(82, 'diploma-christian-ministry', 'Diploma in Christian Ministry', 'Diploma', 'School of Ministry Practice', 'Undergraduate Diploma', 'A practical diploma for ministry leaders, pastors and church workers.', 'This diploma covers preaching, pastoral care, discipleship and mission. Students gain hands-on ministry tools with a strong theological foundation.', '1 year (online)', 'Online', 2900, 'GBP', '/img/generated/gdcu-student-video-lesson-home.webp', 'people', 0, 1, 10, '2026-07-02 16:11:13', '2026-07-02 16:11:13'),
(83, 'diploma-chaplaincy-pastoral-care', 'Diploma in Chaplaincy and Pastoral Care', 'Diploma', 'School of Pastoral Studies', 'Undergraduate Diploma', 'Applied chaplaincy skills for pastoral care in secular and sacred environments.', 'This diploma equips students for chaplaincy and pastoral care roles in hospitals, prisons, schools and community organisations. It combines theology, ethics and practical care.', '1 year (online)', 'Online', 2900, 'GBP', '/img/generated/gdcu-program-leadership-park-v2.webp', 'local_hospital', 0, 1, 11, '2026-07-02 16:11:13', '2026-07-02 16:11:13'),
(84, 'diploma-christian-leadership', 'Diploma in Christian Leadership', 'Diploma', 'School of Global Leadership', 'Undergraduate Diploma', 'Advance your leadership skills for leading teams, churches and faith initiatives.', 'This diploma combines leadership theory, team development and practical church leadership skills. It is ideal for church elders, ministry directors and community leaders.', '1 year (online)', 'Online', 2900, 'GBP', '/img/generated/gdcu-program-mba-home-v2.webp', 'diversity_3', 0, 1, 12, '2026-07-02 16:11:13', '2026-07-02 16:11:13'),
(85, 'diploma-theology-ministry', 'Diploma in Theology and Ministry', 'Diploma', 'School of Global Theology', 'Undergraduate Diploma', 'A balanced diploma in theological reflection and practical ministry.', 'This diploma integrates biblical theology with ministry practice, helping students connect doctrine to daily pastoral and church leadership work.', '1 year (online)', 'Online', 2800, 'GBP', '/img/generated/gdcu-student-admissions-video.webp', 'school', 0, 1, 13, '2026-07-02 16:11:13', '2026-07-02 16:11:13'),
(86, 'diploma-missions-global-christianity', 'Diploma in Missions and Global Christianity', 'Diploma', 'School of Global Theology', 'Undergraduate Diploma', 'Explore contemporary mission, diaspora church growth and global Christian movements.', 'This diploma examines mission practice, global Christianity and diaspora ministry strategies. Students learn to serve diverse communities with cross-cultural competence.', '1 year (online)', 'Online', 2800, 'GBP', '/img/generated/gdcu-program-theology-living-room-v2.webp', 'public', 0, 1, 14, '2026-07-02 16:11:13', '2026-07-02 16:11:13'),
(87, 'diploma-pastoral-counselling-ministry', 'Diploma in Pastoral Counselling for Ministry', 'Diploma', 'School of Pastoral Studies', 'Undergraduate Diploma', 'Counselling approaches for ministry contexts, trauma care and spiritual support.', 'Combining theology and practical counselling, this diploma helps ministers support people through grief, conflict and spiritual struggle.', '1 year (online)', 'Online', 2900, 'GBP', '/img/generated/gdcu-student-courtyard-learning.webp', 'psychology', 0, 1, 15, '2026-07-02 16:11:13', '2026-07-02 16:11:13'),
(88, 'master-christian-theology', 'Master of Christian Theology', 'Masters', 'School of Global Theology', 'Master of Arts', 'Advanced theological study for ministry leaders and scholars.', 'This master’s programme explores doctrinal theology, biblical interpretation and contemporary theological issues. Students build the skills for teaching, research and advanced ministry.', '2 years (part-time, online)', 'Online', 7200, 'GBP', '/img/generated/gdcu-program-theology-living-room-v2.webp', 'menu_book', 1, 1, 16, '2026-07-02 16:11:13', '2026-07-02 16:11:13'),
(89, 'master-christian-ministry', 'Master of Christian Ministry', 'Masters', 'School of Ministry Practice', 'Master of Arts', 'Graduate-level ministry training for holistic pastoral leadership.', 'Designed for experienced ministry leaders, this programme integrates theology, pastoral practice and leadership development for the contemporary church.', '2 years (part-time, online)', 'Online', 7200, 'GBP', '/img/generated/gdcu-program-leadership-park-v2.webp', 'people', 1, 1, 17, '2026-07-02 16:11:13', '2026-07-02 16:11:13'),
(90, 'master-christian-leadership', 'Master of Christian Leadership', 'Masters', 'School of Global Leadership', 'Master of Arts', 'Transformational leadership training for church and mission contexts.', 'This programme focuses on strategic leadership, innovation and character formation for Christian leaders across organisations and ministries.', '2 years (part-time, online)', 'Online', 7200, 'GBP', '/img/generated/gdcu-program-mba-home-v2.webp', 'diversity_3', 1, 1, 18, '2026-07-02 16:11:13', '2026-07-02 16:11:13'),
(91, 'master-chaplaincy-spiritual-care', 'Master of Chaplaincy and Spiritual Care', 'Masters', 'School of Pastoral Studies', 'Master of Arts', 'Advanced chaplaincy training for complex care environments.', 'This master’s programme develops expert chaplains who can provide spiritual care in hospitals, prisons, schools and secular settings with pastoral wisdom and professional competence.', '2 years (part-time, online)', 'Online', 7400, 'GBP', '/img/generated/gdcu-student-courtyard-learning.webp', 'local_hospital', 1, 1, 19, '2026-07-02 16:11:13', '2026-07-02 16:11:13'),
(92, 'master-pastoral-care-counselling-ministry', 'Master of Pastoral Care and Counselling for Ministry', 'Masters', 'School of Pastoral Studies', 'Master of Arts', 'Counselling and pastoral care training for ministry professionals.', 'This programme combines theology and counselling practice, equipping ministers to support emotional and spiritual health in individuals and families.', '2 years (part-time, online)', 'Online', 7400, 'GBP', '/img/generated/gdcu-student-video-lesson-home.webp', 'psychology', 1, 1, 20, '2026-07-02 16:11:13', '2026-07-02 16:11:13'),
(93, 'master-missions-diaspora-ministry', 'Master of Missions and Diaspora Ministry', 'Masters', 'School of Global Theology', 'Master of Arts', 'Advanced study in mission, migration and diaspora church leadership.', 'This programme prepares students to lead mission initiatives among diaspora communities, balancing cultural insight with theological clarity.', '2 years (part-time, online)', 'Online', 7400, 'GBP', '/img/generated/gdcu-program-theology-living-room-v2.webp', 'public', 1, 1, 21, '2026-07-02 16:11:13', '2026-07-02 16:11:13'),
(94, 'bachelor-biblical-studies', 'Bachelor of Biblical Studies', 'Undergraduate', 'School of Global Theology', 'Bachelor of Arts', 'A broad undergraduate degree in biblical languages, literature and theology.', 'This degree offers rigorous study of the Old and New Testament, biblical theology and interpretive methods, preparing students for ministry, teaching and further theological study.', '3 years (online)', 'Online', 5400, 'GBP', '/img/generated/gdcu-student-video-lesson-home.webp', 'menu_book', 0, 1, 22, '2026-07-02 16:11:13', '2026-07-02 16:11:13'),
(95, 'bachelor-christian-ministry', 'Bachelor of Christian Ministry', 'Undergraduate', 'School of Ministry Practice', 'Bachelor of Arts', 'Undergraduate training for the next generation of ministry leaders.', 'This degree combines theology, leadership and practical ministry skills. Students gain preparation for paid and volunteer ministry roles in churches and mission organisations.', '3 years (online)', 'Online', 5400, 'GBP', '/img/generated/gdcu-program-leadership-park-v2.webp', 'people', 0, 1, 23, '2026-07-02 16:11:13', '2026-07-02 16:11:13'),
(96, 'bachelor-christian-leadership', 'Bachelor of Christian Leadership', 'Undergraduate', 'School of Global Leadership', 'Bachelor of Arts', 'Leadership formation for Christian thinkers, organisers and church practitioners.', 'This degree teaches leadership theory, ethics and group dynamics from a Christian perspective, preparing graduates to lead churches, nonprofits and community networks.', '3 years (online)', 'Online', 5400, 'GBP', '/img/generated/gdcu-program-mba-home-v2.webp', 'diversity_3', 0, 1, 24, '2026-07-02 16:11:13', '2026-07-02 16:11:13'),
(97, 'bachelor-chaplaincy-pastoral-care', 'Bachelor of Chaplaincy and Pastoral Care', 'Undergraduate', 'School of Pastoral Studies', 'Bachelor of Arts', 'Undergraduate training for spiritual care, counselling and chaplaincy work.', 'This degree develops compassionate pastoral ministers who can serve in chaplaincy, counselling and church care ministries with maturity and insight.', '3 years (online)', 'Online', 5400, 'GBP', '/img/generated/gdcu-student-courtyard-learning.webp', 'local_hospital', 0, 1, 25, '2026-07-02 16:11:13', '2026-07-02 16:11:13'),
(98, 'bachelor-theology-ministry', 'Bachelor of Theology and Ministry', 'Undergraduate', 'School of Global Theology', 'Bachelor of Arts', 'A broad degree in theology, biblical studies and ministry formation.', 'This degree equips students for ministry, teaching and mission with a strong theological foundation and practical experience.', '3 years (online)', 'Online', 5400, 'GBP', '/img/generated/gdcu-program-theology-living-room-v2.webp', 'school', 0, 1, 26, '2026-07-02 16:11:13', '2026-07-02 16:11:13'),
(99, 'bachelor-missions-global-christianity', 'Bachelor of Missions and Global Christianity', 'Undergraduate', 'School of Global Theology', 'Bachelor of Arts', 'Study global mission, diaspora church and cross-cultural ministry practice.', 'This degree prepares students to serve across cultures and contexts, with theological insight into global Christianity and mission strategy.', '3 years (online)', 'Online', 5400, 'GBP', '/img/generated/gdcu-student-admissions-video.webp', 'public', 0, 1, 27, '2026-07-02 16:11:13', '2026-07-02 16:11:13'),
(100, 'doctorate-christian-ministry', 'Doctor of Christian Ministry', 'Doctorate', 'School of Global Theology', 'Doctor of Ministry', 'Professional doctorate for advanced ministry leadership and practice.', 'This doctoral programme supports experienced ministers in advanced research, reflective leadership and innovation in church and mission practice.', '3–4 years (online, part-time)', 'Online', 8200, 'GBP', '/img/generated/gdcu-news-accreditation-park-v2.webp', 'school', 0, 1, 28, '2026-07-02 16:11:13', '2026-07-02 16:11:13'),
(101, 'doctorate-practical-theology', 'Doctor of Practical Theology', 'Doctorate', 'School of Global Theology', 'Doctor of Philosophy', 'Doctoral research into the practice of faith, church and ministry.', 'This doctoral research degree explores the intersection of theology and practice, equipping scholars to support the church through rigorous applied research.', '3–4 years (online, part-time)', 'Online', 8200, 'GBP', '/img/generated/gdcu-program-leadership-park-v2.webp', 'school', 0, 1, 29, '2026-07-02 16:11:13', '2026-07-02 16:11:13'),
(102, 'doctorate-chaplaincy-spiritual-care', 'Doctor of Chaplaincy and Spiritual Care', 'Doctorate', 'School of Pastoral Studies', 'Doctor of Ministry', 'Advanced practice and research for chaplains and spiritual care leaders.', 'This doctorate develops expert chaplains who can lead spiritual care ministries in complex organisations and research the field of spiritual care.', '3–4 years (online, part-time)', 'Online', 8200, 'GBP', '/img/generated/gdcu-student-courtyard-learning.webp', 'local_hospital', 0, 1, 30, '2026-07-02 16:11:13', '2026-07-02 16:11:13'),
(103, 'doctorate-christian-leadership', 'Doctor of Christian Leadership', 'Doctorate', 'School of Global Leadership', 'Doctor of Philosophy', 'Research-based leadership doctorate for church and nonprofit leaders.', 'This doctoral programme helps leaders develop original research in Christian leadership, organisational transformation and mission innovation.', '3–4 years (online, part-time)', 'Online', 8200, 'GBP', '/img/generated/gdcu-program-mba-home-v2.webp', 'diversity_3', 0, 1, 31, '2026-07-02 16:11:13', '2026-07-02 16:11:13'),
(104, 'ba-theology-ministry', 'BA Theology & Ministry', 'Undergraduate', 'School of Global Theology', 'Bachelor of Arts', 'A foundational degree in biblical studies, theology and practical ministry for the next generation of Christian leaders.', 'The BA Theology & Ministry provides a thorough grounding in biblical languages, church history, systematic theology and pastoral practice. Designed for flexible online study, it equips students for ordained ministry, missions and lay leadership.', '3 years (online)', 'Online', 5400, 'GBP', '/img/generated/gdcu-student-video-lesson-home.webp', 'menu_book', 0, 1, 32, '2026-07-02 16:11:13', '2026-07-02 16:11:13'),
(105, 'msc-business-administration', 'MBA — Faith-Led Business', 'Masters', 'School of Business & Enterprise', 'Master of Business Administration', 'Lead enterprises with integrity, combining rigorous business strategy with a Christian ethic of stewardship.', 'A practical MBA for entrepreneurs and managers who want to build profitable, ethical organisations. Covers strategy, finance, marketing, operations and ethical leadership, with a focus on the diaspora economy.', '2 years (part-time, online)', 'Online', 7600, 'GBP', '/img/generated/gdcu-program-mba-home-v2.webp', 'business_center', 1, 1, 33, '2026-07-02 16:11:13', '2026-07-02 16:11:13');
