(18841, 4792, 'Pastoral counselling addresses ordinary spiritual and relational struggles but is not a substitute for licensed clinical care.', 1, 1),
(18842, 4792, 'Pastoral counselling fully replaces the need for any professional mental-health treatment.', 0, 2),
(18843, 4792, 'Pastoral counselling and clinical treatment address entirely unrelated aspects of a person and never overlap.', 0, 3),
(18844, 4792, 'Referral to professionals indicates a lack of faith and should generally be avoided.', 0, 4),
(18845, 4793, 'Offering advice as quickly as possible so the person is not left in doubt.', 0, 1),
(18846, 4793, 'Being swift to hear and slow to speak, that is, the primacy of listening.', 1, 2),
(18847, 4793, 'Correcting the person\'s theological errors before addressing their feelings.', 0, 3),
(18848, 4793, 'Keeping conversations brief so the counsellor avoids emotional fatigue.', 0, 4),
(18849, 4794, 'That suffering people should be given detailed explanations of their pain.', 0, 1),
