(19165, 4873, 'Offering advice as quickly as possible so the person is not left in doubt.', 0, 1),
(19166, 4873, 'Being swift to hear and slow to speak, that is, the primacy of listening.', 1, 2),
(19167, 4873, 'Correcting the person\'s theological errors before addressing their feelings.', 0, 3),
(19168, 4873, 'Keeping conversations brief so the counsellor avoids emotional fatigue.', 0, 4),
(19169, 4874, 'That suffering people should be given detailed explanations of their pain.', 0, 1),
(19170, 4874, 'That counsellors should avoid physical proximity to those who grieve.', 0, 2),
(19171, 4874, 'That quiet presence can minister more deeply than words, and premature explanations may harm.', 1, 3),
(19172, 4874, 'That silence is generally a sign of a counsellor\'s incompetence.', 0, 4),
(19173, 4875, 'When the counsellor finds the person\'s story unusually interesting.', 0, 1),
(19174, 4875, 'When another church member casually asks how the counselling is going.', 0, 2),
(19175, 4875, 'When the counsellor wishes to illustrate a point in a sermon.', 0, 3),
(19176, 4875, 'When there is a serious risk of harm to the person or to others, or the law requires disclosure.', 1, 4),
(19177, 4876, 'As an honourable act of love and prudence, ideally with the pastoral relationship continuing alongside professional care.', 1, 1),
(19178, 4876, 'As a last resort that signals the counsellor\'s spiritual failure.', 0, 2),
(19179, 4876, 'As a complete handover after which the counsellor should end all contact.', 0, 3),
(19180, 4876, 'As something to be delayed as long as possible to demonstrate faith.', 0, 4);
