INSERT INTO `assignments` (`id`, `course_id`, `title`, `instructions`, `due_date`, `max_points`, `published`, `created_at`, `updated_at`, `module_id`, `lesson_block_id`, `sort_order`, `assignment_type`) VALUES
(128, 23, 'Interpreting a Passage in Context', 'Select one short biblical passage of five to ten verses from any book of your choosing. In roughly 800 words, identify its literary genre and its historical and literary context, then explain what the passage most likely meant to its original audience before proposing one faithful application for readers today. Demonstrate exegesis rather than eisegesis by grounding every claim in the text and its context, and cite the specific verses you discuss.', 1784237799352, 100, 1, '2026-07-02 21:36:39', '2026-07-02 21:36:39', NULL, NULL, 1, 'essay'),
(129, 23, 'Tracing a Doctrine from Scripture to Confession', 'Choose one central doctrine from this module (the Trinity, the person of Christ, or salvation) and write a 900-1200 word essay explaining it. Ground your explanation in at least three specific Scripture references and show how the church clarified the doctrine through a creed or council (for example, Nicaea, Constantinople, or Chalcedon). Conclude by explaining, in your own words, why this doctrine matters for Christian worship or daily life, engaging at least two Christian traditions in an irenic and charitable manner.', 1785447399352, 100, 1, '2026-07-02 21:36:39', '2026-07-02 21:36:39', NULL, NULL, 2, 'essay'),
(130, 23, 'Tracing a Thread Through Church History', 'Choose one theme (for example, the authority of Scripture, the relationship between Church and state, worship and the sacraments, or Christian mission) and trace its development across the three periods studied in this module: the early Church, the medieval and Reformation era, and the modern global Church. In roughly 1000–1200 words, explain how the theme was understood in each period, citing at least two specific historical figures or events and at least two Scripture passages. Conclude by reflecting on what this history teaches Christians today, writing irenically about the traditions involved.', 1786656999352, 100, 1, '2026-07-02 21:36:39', '2026-07-02 21:36:39', NULL, NULL, 3, 'essay'),
(131, 23, 'Interpreting a Passage in Context', 'Select a single biblical passage of roughly 6 to 12 verses and write a 900 to 1200 word interpretive essay applying the method developed in this module. Identify the passage\'s genre and literary context, describe the relevant historical background of its author and audience, and state the meaning it would have carried for its original hearers. Then, using the principle-versus-form distinction, articulate one enduring theological or moral principle and propose a faithful, well-reasoned application for the church today, citing Scripture inline to support your reasoning.', 1787866599353, 100, 1, '2026-07-02 21:36:39', '2026-07-02 21:36:39', NULL, NULL, 4, 'essay'),
(132, 23, 'A Theology and Self-Assessment of Ministry', 'In 900-1200 words, articulate your own working definition of Christian ministry, grounding it in at least four Scripture passages studied in this module and explaining how ministry both belongs to the whole people of God and is served by recognized leaders. Then apply the module honestly to yourself: identify which of the four core practices (word, worship, care, mission) you are most drawn to, which of the three perils (pride, burnout, hypocrisy) poses the greatest risk to you, and one concrete safeguard you will adopt. Engage at least one point where Christian traditions differ, treating it irenically and fairly.', 1789076199353, 100, 1, '2026-07-02 21:36:39', '2026-07-02 21:36:39', NULL, NULL, 5, 'essay'),
(133, 23, 'Designing a Personal Rule of Life', 'Drawing on all three Parts of this module, compose a 900–1200 word personal rule of life that names your intended goal of formation, selects a sustainable rhythm of at least one discipline of engagement and one of abstinence, and identifies a specific community and relationship of mutual discipleship in which you will pursue it. Explain the theological rationale for each choice, citing at least three passages of Scripture and interacting with at least one concept from the module (for example, grace and effort, the means of grace, or vocation). Conclude by addressing how your plan guards against both passive quietism and legalistic striving.', 1790285799353, 100, 1, '2026-07-02 21:36:39', '2026-07-02 21:36:39', NULL, NULL, 6, 'essay'),
(134, 24, 'Interpreting a Passage in Context', 'Select one short biblical passage of five to ten verses from any book of your choosing. In roughly 800 words, identify its literary genre and its historical and literary context, then explain what the passage most likely meant to its original audience before proposing one faithful application for readers today. Demonstrate exegesis rather than eisegesis by grounding every claim in the text and its context, and cite the specific verses you discuss.', 1784237799385, 100, 1, '2026-07-02 21:36:39', '2026-07-02 21:36:39', NULL, NULL, 1, 'essay'),
